  8Ôćĺimport org.wordpress.android.ui.deeplinks.DeepLinkNavigator.NavigateAction.OpenStatsForTimeframe
  9Ôćĺimport org.wordpress.android.ui.deeplinks.DeepLinkNavigator.NavigateAction.OpenJetpackStaticPosterView
 10Ôćĺimport org.wordpress.android.ui.deeplinks.DeepLinkUriUtils
 11Ôćĺimport org.wordpress.android.ui.deeplinks.DeepLinkingIntentReceiverViewModel.Companion.APPLINK_SCHEME
 12Ôćĺimport org.wordpress.android.ui.deeplinks.DeepLinkingIntentReceiverViewModel.Companion.HOST_WORDPRESS_COM
 13Ôćĺimport org.wordpress.android.ui.deeplinks.DeepLinkingIntentReceiverViewModel.Companion.SITE_DOMAIN
 14Ôćĺimport org.wordpress.android.ui.jetpackoverlay.JetpackFeatureRemovalPhaseHelper
 15Ôćĺimport org.wordpress.android.ui.stats.StatsTimeframe
 16Ôćĺimport org.wordpress.android.util.UriWrapper
 17Ôćĺimport javax.inject.Inject
 18Ôćĺ
 19Ôćĺclass StatsLinkHandler
 20Ôćĺ@Inject constructor(
 21Ôćĺ    private val deepLinkUriUtils: DeepLinkUriUtils,
 22Ôćĺ    private val jetpackFeatureRemovalPhaseHelper: JetpackFeatureRemovalPhaseHelper
 23Ôćĺ) : DeepLinkHandler {
 24Ôćĺ    /**
 25Ôćĺ     * Builds navigate action from URL like:
 26Ôćĺ     * https://wordpress.com/stats/$timeframe/$site
 27Ôćĺ     * where timeframe and site are optional
 28Ôćĺ     * or
 29Ôćĺ     * wordpress://stats
 30Ôćĺ     */
 31Ôćĺ    override fun buildNavigateAction(uri: UriWrapper): NavigateAction {
 32Ôćĺ        val pathSegments = uri.pathSegments
 33Ôćĺ        val length = pathSegments.size
 34Ôćĺ        val site = pathSegments.getOrNull(length - 1)?.toSite()
 35Ôćĺ        val statsTimeframe = pathSegments.getOrNull(length - 2)?.toStatsTimeframe()
 36Ôćĺ        return when {
 37Ôćĺ            jetpackFeatureRemovalPhaseHelper.shouldShowStaticPage() -> OpenJetpackStaticPosterView
 38Ôćĺ            site != null && statsTimeframe != null -> {
 39Ôćĺ                OpenStatsForSiteAndTimeframe(site, statsTimeframe)
 40Ôćĺ            }
 41Ôćĺ            site != null -> {
 42Ôćĺ                OpenStatsForSite(site)
 43Ôćĺ            }
 44Ôćĺ            statsTimeframe != null -> {
 45Ôćĺ                OpenStatsForTimeframe(statsTimeframe)
 46Ôćĺ            }
 47Ôćĺ            else -> {
 48Ôćĺ                // In other cases, launch stats with the current selected site.
 49Ôćĺ                OpenStats
 50Ôćĺ            }
 51Ôćĺ        }
 52Ôćĺ    }
 53Ôćĺ
 54Ôćĺ    /**
 55Ôćĺ     * Returns true if the URI should be handled by StatsLinkHandler.
 56Ôćĺ     * The handled links are `https://wordpress.com/stats/day/$site` and `wordpress://stats`
 57Ôćĺ     */
 58Ôćĺ    override fun shouldHandleUrl(uri: UriWrapper): Boolean {
 59Ôćĺ        return (uri.host == HOST_WORDPRESS_COM &&
 60Ôćĺ                uri.pathSegments.firstOrNull() == STATS_PATH) || uri.host == STATS_PATH
 61Ôćĺ    }
 62Ôćĺ
 63Ôćĺ    override fun stripUrl(uri: UriWrapper): String {
 64Ôćĺ        return buildString {
 65Ôćĺ            val offset = if (uri.host == STATS_PATH) {
 66Ôćĺ                append(APPLINK_SCHEME)
 67Ôćĺ                0
 68Ôćĺ            } else {
 69Ôćĺ                append("$HOST_WORDPRESS_COM/")
 70Ôćĺ                1
 71Ôćĺ            }
 72Ôćĺ            append(STATS_PATH)
 73Ôćĺ            val pathSegments = uri.pathSegments
 74Ôćĺ            val size = pathSegments.size
 75Ôćĺ            val statsTimeframe = if (size > offset) pathSegments.getOrNull(offset) else null
 76Ôćĺ            val hasSiteUrl = if (size > offset + 1) pathSegments.getOrNull(offset + 1) != null else false
 77Ôćĺ            if (statsTimeframe != null) {
 78Ôćĺ                append("/$statsTimeframe")
 79Ôćĺ            }
 80Ôćĺ            if (hasSiteUrl) {
 81Ôćĺ                append("/$SITE_DOMAIN")
 82Ôćĺ            }
 83Ôćĺ        }
 84Ôćĺ    }
 85Ôćĺ
 86Ôćĺ    /**
 87Ôćĺ     * Converts HOST name of a site to SiteModel. It finds the Site in the current local sites and matches the name
 88Ôćĺ     * to the host.
 89Ôćĺ     */
 90Ôćĺ    private fun String.toSite(): SiteModel? {
 91Ôćĺ        return deepLinkUriUtils.hostToSite(this)
 92Ôćĺ    }
 93Ôćĺ
 94Ôćĺ    private fun String.toStatsTimeframe(): StatsTimeframe? {
 95Ôćĺ        return when (this) {
 96Ôćĺ            "day" -> StatsTimeframe.DAY
 97Ôćĺ            "week" -> StatsTimeframe.WEEK
 98Ôćĺ            "month" -> StatsTimeframe.MONTH
 99Ôćĺ            "year" -> StatsTimeframe.YEAR
100Ôćĺ            "insights" -> StatsTimeframe.INSIGHTS
101Ôćĺ            else -> null
102Ôćĺ        }
103Ôćĺ    }
104Ôćĺ
105Ôćĺ    companion object {
106Ôćĺ        private const val STATS_PATH = "stats"
107Ôćĺ    }
108Ôćĺ}
